import axios from 'axios';
import React, { useState } from 'react';

function SOSButton() {
  const [confirm, setConfirm] = useState(false);
  const [status, setStatus] = useState(null);

  // ... keep existing handleSendSOS logic ...

  return (
    <>
      {/* Floating Button at bottom right */}
      <div className="fixed bottom-8 right-8 z-50">
        <button
          onClick={() => setConfirm(true)}
          className="relative flex items-center justify-center w-16 h-16 bg-red-600 text-white rounded-full shadow-[0_0_20px_rgba(220,38,38,0.5)] hover:bg-red-700 hover:scale-110 transition-all duration-300"
        >
          {/* Pulsing ring effect */}
          <span className="absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75 animate-ping"></span>
          <span className="relative text-2xl">⚠️</span>
        </button>
      </div>

      {/* Beautiful Modal Overlay */}
      {confirm && (
        <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4 transition-opacity">
          <div className="bg-white p-8 rounded-2xl shadow-2xl text-center space-y-6 max-w-sm w-full transform transition-all scale-100">
            <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <span className="text-3xl">🚨</span>
            </div>
            
            <div>
              <h3 className="text-2xl font-bold text-gray-900">Emergency SOS</h3>
              <p className="text-gray-500 mt-2 text-sm">
                This will alert your emergency contacts and share your live location. Are you sure?
              </p>
            </div>

            <div className="flex flex-col space-y-3 mt-6">
              <button
                onClick={handleSendSOS}
                className="w-full bg-red-600 text-white font-bold py-3 rounded-xl hover:bg-red-700 shadow-md active:scale-95 transition-all"
              >
                Send SOS Now
              </button>
              <button
                onClick={() => setConfirm(false)}
                className="w-full bg-gray-100 text-gray-700 font-semibold py-3 rounded-xl hover:bg-gray-200 transition-all"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notification for Status */}
      {status && (
        <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 bg-gray-800 text-white px-6 py-3 rounded-full shadow-lg z-50 animate-bounce">
          {status}
        </div>
      )}
    </>
  );
}

export default SOSButton;
